import { mkdir, writeFile } from "node:fs/promises";
import { dirname, join, resolve } from "node:path";
export function normalizeModules(input) {
    return (input !== null && input !== void 0 ? input : "tenancy,auth,rbac,audit,inventory,crm,websites")
        .split(",")
        .map((part) => part.trim())
        .filter(Boolean);
}
export function createPackageJson(name) {
    return JSON.stringify({
        name,
        private: true,
        version: "0.1.0",
        scripts: {
            dev: "next dev",
            build: "next build",
            start: "next start",
        },
        dependencies: {
            next: "16.2.2",
            react: "19.2.4",
            "react-dom": "19.2.4",
        },
    }, null, 2);
}
export function createRuntimeTemplate(options) {
    const moduleLines = options.modules.map((moduleName) => `// - ${moduleName}`).join("\n");
    return `export const appDefinition = {
  name: "${options.name}",
  modules: [
${options.modules.map((moduleName) => `    "${moduleName}"`).join(",\n")}
  ],
};

/*
Selected modules
${moduleLines}
*/
`;
}
export function createReadme(options) {
    return `# ${options.name}

Generated by create-vims-app.

Enabled modules:
${options.modules.map((moduleName) => `- ${moduleName}`).join("\n")}
`;
}
export function createTsConfig() {
    return JSON.stringify({
        compilerOptions: {
            target: "ES2017",
            lib: ["dom", "dom.iterable", "esnext"],
            allowJs: false,
            skipLibCheck: true,
            strict: true,
            noEmit: true,
            esModuleInterop: true,
            module: "esnext",
            moduleResolution: "bundler",
            resolveJsonModule: true,
            isolatedModules: true,
            jsx: "react-jsx",
            incremental: true,
        },
        include: ["**/*.ts", "**/*.tsx"],
        exclude: ["node_modules"],
    }, null, 2);
}
export function createNextConfig() {
    return `import type { NextConfig } from "next";

const nextConfig: NextConfig = {
  reactCompiler: true,
};

export default nextConfig;
`;
}
export function createLayoutTemplate(name) {
    return `import "./globals.css";

export const metadata = {
  title: "${name}",
  description: "Generated by create-vims-app",
};

export default function RootLayout({
  children,
}: Readonly<{ children: React.ReactNode }>) {
  return (
    <html lang="en">
      <body>{children}</body>
    </html>
  );
}
`;
}
export function createPageTemplate(name) {
    return `import { appDefinition } from "@/lib/app-definition";

export default function Page() {
  return (
    <main style={{ padding: "3rem", fontFamily: "sans-serif" }}>
      <h1>${name}</h1>
      <p>Generated by create-vims-app.</p>
      <pre>{JSON.stringify(appDefinition, null, 2)}</pre>
    </main>
  );
}
`;
}
export function createGlobalCss() {
    return `html, body {
  margin: 0;
  min-height: 100%;
}

body {
  background: #f5f1e8;
  color: #13212c;
}
`;
}
export function createEnvExample() {
    return `POSTGRES_URL=postgres://postgres:postgres@127.0.0.1:5432/vims
REDIS_URL=redis://127.0.0.1:6379
VIMS_ENABLED_MODULES=
VIMS_ENABLED_PROVIDERS=
`;
}
export function createScaffoldFiles(options) {
    return [
        {
            path: "package.json",
            content: createPackageJson(options.name),
        },
        {
            path: "tsconfig.json",
            content: createTsConfig(),
        },
        {
            path: "next.config.ts",
            content: createNextConfig(),
        },
        {
            path: ".env.example",
            content: createEnvExample(),
        },
        {
            path: "README.md",
            content: createReadme(options),
        },
        {
            path: "src/lib/app-definition.ts",
            content: createRuntimeTemplate(options),
        },
        {
            path: "src/app/layout.tsx",
            content: createLayoutTemplate(options.name),
        },
        {
            path: "src/app/page.tsx",
            content: createPageTemplate(options.name),
        },
        {
            path: "src/app/globals.css",
            content: createGlobalCss(),
        },
    ];
}
export async function writeScaffold(outputDir, options) {
    const targetDir = resolve(outputDir, options.name);
    const files = createScaffoldFiles(options);
    for (const file of files) {
        const targetPath = join(targetDir, file.path);
        await mkdir(dirname(targetPath), { recursive: true });
        await writeFile(targetPath, file.content, "utf8");
    }
    return {
        targetDir,
        files: files.map((file) => join(targetDir, file.path)),
    };
}
